<?php $url = "https://unknowing-relight-civic.ngrok-free.dev/API/announcements/bill_master.php"; $cucodes = App\Models\Customer::whereNotNull("external_cucode")->pluck("external_cucode")->toArray(); foreach($cucodes as $c) { $ch = curl_init($url); curl_setopt($ch, CURLOPT_POST, 1); curl_setopt($ch, CURLOPT_POSTFIELDS, ["cucode" => $c, "from_date" => "2026-01-01", "to_date" => "2026-06-02"]); curl_setopt($ch, CURLOPT_HTTPHEADER, ["ngrok-skip-browser-warning: true"]); curl_setopt($ch, CURLOPT_RETURNTRANSFER, true); $res = curl_exec($ch); if(strpos($res, "BILLNO") !== false) { echo "$c: $res\n"; break; } }
